#include<bits/stdc++.h>
using namespace std;

int n,a[16500],f[16005],ans=-2147483647;
vector <int> e[16005];
void dfs(int u,int fa)
{
	f[u]=a[u];
	for(int i=0;i<e[u].size();i++){
		int t=e[u][i];
		if(t!=fa){
			dfs(t,u);
			if(f[t]>0){
				f[u]+=f[t];
			}
		}
	}
}
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	for(int i=1;i<n;i++){
		int u,v;
		cin>>u>>v;
		e[u].push_back(v);
		e[v].push_back(u);
	}
	dfs(1,0);
	for(int i=1;i<=n;i++){
		ans=max(ans,f[i]);
	}
	cout<<ans;
	return 0;
}
